var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배. 아까 전투 중에 한 말은 무슨 뜻이야?","JPN":"先輩、さっき戦闘中に言ってたことってどういう意味？","ENG":"Shiyoon, what did you mean by what you said earlier during the battle?","TWN":"前輩，你剛剛在戰鬥中說的話是什麼意思？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"인형놀이를 즐기는 사람이 근처에 있다니? 난 인형 비슷한 것도 못 봤는데.","JPN":"人形遊びが好きな人が近くにいるって？　人形みたいなものも見えなかったけど。","ENG":"Something about somebody who likes to play with puppets nearby? I didn’t see any puppets out there.","TWN":"附近有喜歡木偶遊戲的人嗎？我沒看到木偶啊？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 조금 전까지 싸워놓고 그렇게 말씀하시면 곤란하죠.","JPN":"ハハ、さっきまで戦ってたのにそう言われると困ります。","ENG":"Haha, it's a little awkward hearing you say that after fighting them yourself not too long ago.","TWN":"哈哈，你才剛跟人家打完，現在還問這種問題喔？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 설마 저 침식체들 말이야?","JPN":"えっ？　まさかあの侵食体のこと？","ENG":"What? You mean those Corrupted Objects?","TWN":"什麼意思？該不會是指剛剛那些侵蝕體吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 정교하게 만들어지긴 했지만 이건 자연적으로 발생한 침식체가 아니에요.","JPN":"そうです。精巧に作られていましたが、これは自然に発生した侵食体ではありません。","ENG":"Yes. Although they have been intricately made, those were not naturally occurring Corrupted Objects.","TWN":"對，雖然做得很精細，但不是自然形成的侵蝕體。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"누군가가 만들어낸 사역마 같은 존재입니다.","JPN":"誰かが作った使い魔みたいな存在です。","ENG":"They were similar to familiars created by someone.","TWN":"是某人弄出來的一種類似分身的型態。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 전혀 구분 못하겠던데…… 선배는 어떻게 알아차린 거야?","JPN":"全然見分けがつかないけど……先輩はどうやってわかったの？","ENG":"I couldn’t tell the difference at all... How did you figure it out?","TWN":"我完全分辨不出來欸……前輩是怎麼看出來的？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"간단해요. 여기를 잘 보시면 어떤 에너지가 실처럼 연결되어 있거든요.","JPN":"簡単です。ここをよく見ると何らかのエネルギーが糸のように繋がっているんです。","ENG":"It’s simple. If you take a closer look here, there’s a string of some energy connected to it.","TWN":"很簡單，你仔細看這裡，是不是連著某種能量像一條線一樣。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실……?","JPN":"糸……？","ENG":"A string...?","TWN":"線……？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으으으음…….","JPN":"うううう～む……","ENG":"Hmm...","TWN":"呃呃……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자세히 보니 뭔가…… 녀석들 주변에 투명한 끈이 보이는 것 같기도 하고…….","JPN":"よく見ると何だか……やつらの周りに透明な紐が見えるような気もするけど……","ENG":"Now that you mention it... I think I see some kind of transparent string around them...","TWN":"仔細看……那些傢伙周圍似乎有條透明的線沒錯……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, C급 카운터의 능력으로는 식별하기 어려운 미세한 에너지인데 간단히 알아보시네요.","JPN":"ハハ、C級カウンターの能力では識別が難しい、微弱なエネルギーなんですけど、すぐにわかっちゃいましたね。","ENG":"Haha, it’s faint, so it’s difficult to identify even with the abilities of a grade C Counter, but you found it quite easily.","TWN":"哈哈，以C級制裁者的能力，應該很難分辨出這麼細微的能量，你卻輕易就能夠看出來。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 미나 양은 성장이 빨라요.","JPN":"やっぱりミナさんは成長が早い。","ENG":"You are truly a fast learner.","TWN":"米娜果然成長得很快速呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그냥 눈에 보이는 거잖아? 굳이 급수를 따질만한 일도 아닌걸.","JPN":"普通に見えるものでしょ？　あえてランクを云々する程のことでもないと思うけど。","ENG":"You can plainly see that it’s there. I don’t think that it’s something which warrants a discussion regarding my grade.","TWN":"不就是用眼睛看嗎？跟什麼級有什麼關係！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……뭐, 그렇다고 해 두죠.","JPN":"……まあ、そういうことにしておきましょうか。","ENG":"...If you say so.","TWN":"……你要這麼說也是啦。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무튼 이건, 누군가가 이 침식체들을 조종하고 있었다는 뜻입니다.","JPN":"とにかく、これは誰かがこの侵食体を操っていたということです。","ENG":"Anyway, this means that somebody is controlling these Corrupted Objects.","TWN":"總之，我要說的是，一定是有人在控制那些侵蝕體。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"예전에 선배가 사용하던 그 기분 나쁜 기술처럼?","JPN":"以前、先輩が使ったあの気持ち悪い技みたいに？","ENG":"You mean like that creepy ability you used to use?","TWN":"就像前輩之前用過的那個糟糕技術嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……용혈과는 달라요.","JPN":"……言霊とは違います。","ENG":"...This is different from Power Words.","TWN":"……那可不一樣。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};